DROP TABLE IF EXISTS `vw_customer_profile_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_customer_profile_summary`  AS SELECT `cp`.`id` AS `id`, `cp`.`customer_id` AS `customer_id`, `cp`.`customer_type` AS `customer_type`, `cp`.`full_name` AS `full_name`, `cp`.`email` AS `email`, `cp`.`contact` AS `contact`, `cp`.`status` AS `status`, `u`.`full_name` AS `created_by_name`, `cp`.`province` AS `province`, `cp`.`sol` AS `sol`, `cp`.`created_at` AS `created_at`, count(distinct `b`.`id`) AS `borrower_count`, count(distinct `g`.`id`) AS `guarantor_count`, count(distinct `c`.`id`) AS `collateral_count`, count(distinct `ld`.`id`) AS `loan_count` FROM (((((`customer_profiles` `cp` left join `users` `u` on(`cp`.`created_by` = `u`.`id`)) left join `borrowers` `b` on(`cp`.`id` = `b`.`customer_profile_id`)) left join `guarantors` `g` on(`cp`.`id` = `g`.`customer_profile_id`)) left join `collateral` `c` on(`cp`.`id` = `c`.`customer_profile_id`)) left join `loan_details` `ld` on(`cp`.`id` = `ld`.`customer_profile_id`)) GROUP BY `cp`.`id`, `cp`.`customer_id`, `cp`.`customer_type`, `cp`.`full_name`, `cp`.`email`, `cp`.`contact`, `cp`.`status`, `u`.`full_name`, `cp`.`province`, `cp`.`sol`, `cp`.`created_at` ;

